solution_code:
#include <iostream>

int main() {
    int a { 10 };
    int b { 20 };

    int*       ptr1 { &a }; // plain pointer: can reseat, can modify
    int* const ptr2 { &a }; // const pointer: cannot reseat, can modify
    const int* ptr3 { &a }; // pointer to const: can reseat, cannot modify

    // Demonstrate that the pointer types are correct:
    ptr1 = &b;   // ok
    *ptr1 = 5;   // ok
    // ptr2 = &b; // would not compile
    *ptr2 = 7;   // ok
    ptr3 = &b;   // ok
    // *ptr3 = 9; // would not compile

    std::cout << "ptr1: reseat=yes modify=yes\n";
    std::cout << "ptr2: reseat=no  modify=yes\n";
    std::cout << "ptr3: reseat=yes modify=no \n";

    return 0;
}

