#include <iostream>

int main() {
    int a {};
    int b {};
    std::cin >> a >> b;

    // Use a temporary to swap
    int tmp { a };
    a = b;
    b = tmp;

    // Observer — should only read, never write
    const int* observer { &a };
    std::cout << "After swap: " << *observer << '\n';
    observer = &b;   // FIX: point at b to print its value
    std::cout << "After swap: " << *observer << '\n';

    return 0;
}
